import asyncio

# WRONG: silently discards the timeout
async def bad_handler():
    try:
        return await asyncio.wait_for(expensive_llm_call(), timeout=10.0)
    except Exception:       # catches TimeoutError — silent failure
        return None         # caller has no idea what happened

# CORRECT: catch specifically, log, and decide: raise, fallback, or partial result
async def good_handler():
    try:
        return await asyncio.wait_for(expensive_llm_call(), timeout=10.0)
    except asyncio.TimeoutError:
        print("[WARN] LLM call timed out after 10s")
        raise   # let the orchestrator decide the fallback strategy
